const jwt = require('jsonwebtoken');

const authenticate = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  try {
    req.user = jwt.verify(authHeader.substring(7), process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: process.env.JWT_ISSUER,
    });
    next();
  } catch {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
};

app.get('/users', authenticate, (req, res) => { ... });
```

---

### 2. PII Exposed Without Encryption (A02)
**Lines 11–16** — Real names and email addresses are returned unauthenticated over plain HTTP, violating GDPR/privacy requirements.

**Fix:** Protect the endpoint (see #1) and ensure only necessary fields are returned. Never transmit PII over unencrypted HTTP.

---

### 3. No HTTPS Enforcement (A02)
**Lines 18–20** — The server listens on plain HTTP. All traffic, including any future credentials or PII, is vulnerable to man-in-the-middle attacks.

**Fix:**
```javascript
const https = require('https');
const fs = require('fs');

if (process.env.NODE_ENV === 'production') {
  const options = {
    key: fs.readFileSync(process.env.SSL_KEY_PATH),
    cert: fs.readFileSync(process.env.SSL_CERT_PATH),
  };
  https.createServer(options, app).listen(443);

  // Redirect HTTP → HTTPS
  const httpApp = express();
  httpApp.use((req, res) => res.redirect(301, `https://${req.headers.host}${req.url}`));
  httpApp.listen(80);
} else {
  app.listen(3000);
}
```

---

### 4. Health Endpoint Leaks Server Timestamp (A05)
**Lines 7–9** — The `/health` endpoint exposes the server's current timestamp. While seemingly minor, this aids attackers in fingerprinting the server and can help with timing attacks or JWT replay calculations.

**Fix:**
```javascript
// Before
res.json({ status: 'ok', timestamp: new Date().toISOString() });

// After — remove internal server details from public endpoints
res.json({ status: 'ok' });
```

---

## 🟠 High Findings

### 5. Missing Security Headers & No CORS Policy (A05)
No `helmet` or CORS middleware is present. The defaults allow any origin, expose server internals, and omit headers like `X-Frame-Options`, `X-Content-Type-Options`, and `Strict-Transport-Security`.

**Fix:**
```javascript
const helmet = require('helmet');
const cors = require('cors');

app.use(helmet()); // Sets ~14 security headers automatically

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || [],
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
}));
```

---

### 6. No Rate Limiting / DoS Protection (A01)
No throttling exists on any endpoint. An attacker can flood the server with requests causing resource exhaustion.

**Fix:**
```javascript
const rateLimit = require('express-rate-limit');

app.use(rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
}));
```

---

### 7. No Security Logging or Monitoring (A09)
No request logging, no auth-failure tracking, no anomaly detection. Without this, breaches go undetected.

**Fix:**
```javascript
const winston = require('winston');
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.File({ filename: 'combined.log' })],
});

// Request logging middleware
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => logger.info({
    method: req.method, path: req.path,
    status: res.statusCode, duration: Date.now() - start,
    ip: req.ip,
  }));
  next();
});
```

---

## 🟡 Medium Findings

### 8. No Request Body Size Limits (A05)
No `express.json()` or `express.urlencoded()` with size limits — a large payload body can exhaust server memory.

**Fix:**
```javascript
app.use(express.json({ limit: '100kb' }));
app.use(express.urlencoded({ limit: '100kb', extended: true }));
```

---

### 9. No Centralized Error Handling / Stack Trace Leakage (A05)
Unhandled exceptions will bubble up as default Express 500 errors, potentially leaking stack traces, file paths, and library versions.

**Fix:**
```javascript
// Must be last middleware registered
app.use((err, req, res, next) => {
  logger.error({ message: err.message, stack: err.stack, path: req.path });
  res.status(err.status || 500).json(
    process.env.NODE_ENV === 'development'
      ? { error: err.message, stack: err.stack }
      : { error: 'Internal server error' }
