  res.json([...]);
});

// ✅ Fix — add authentication middleware
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Forbidden' });
  }
};

app.get('/users', authenticate, (req, res) => {
  res.json([...]);
});
```

---

### 🟠 High

#### 2. Security Misconfiguration — No Security Headers (OWASP A05)
No HTTP security headers are set. This exposes users to clickjacking, MIME sniffing, XSS, and information leakage via the `X-Powered-By: Express` header.

```js
// ✅ Fix — add helmet (sets ~14 headers automatically)
const helmet = require('helmet');
app.use(helmet()); // Adds CSP, X-Frame-Options, HSTS, removes X-Powered-By, etc.
```

#### 3. Security Misconfiguration — No CORS Policy (OWASP A05)
Without explicit CORS configuration, browsers apply no Same-Origin protections server-side. A malicious site could freely call your API from a victim's browser.

```js
// ✅ Fix — explicitly restrict allowed origins
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGIN || 'https://yourdomain.com',
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

#### 4. Insecure Design — No Rate Limiting (OWASP A04)
Both endpoints are unthrottled. `/users` can be scraped without limit; `/health` can be used for reconnaissance or to drive a DoS.

```js
// ✅ Fix — apply rate limiting
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 🟡 Medium

#### 5. Security Logging & Monitoring Failures (OWASP A09)
There is no request logging and no error handling. Attackers can probe and enumerate the API with zero visibility, and any unhandled error will expose an Express stack trace to the client.

```js
// ✅ Fix — add structured logging and a global error handler
const morgan = require('morgan');
app.use(morgan('combined')); // or use a structured logger like winston/pino

// Global error handler — must be defined LAST, after all routes
app.use((err, req, res, next) => {
  console.error(err.stack); // log internally
  res.status(500).json({ error: 'Internal Server Error' }); // never expose stack to client
});
```

#### 6. Information Exposure via `/health` Endpoint (OWASP A05)
The health endpoint returns a precise server timestamp. While low-risk alone, timestamps assist timing-based attacks and server fingerprinting. Additionally, health endpoints should be protected from external access in production.

```js
// ✅ Fix — omit sensitive fields, optionally restrict to internal network
app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // remove timestamp, or gate it behind auth
});
```

#### 7. Missing Input Validation Middleware (OWASP A03)
No `express.json()` or `express.urlencoded()` body parser is registered. If POST/PUT routes are ever added without this review, malformed payloads and prototype pollution attacks become possible immediately.

```js
// ✅ Fix — declare parsers explicitly with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

