  // Strip sensitive fields before responding
  const safeUsers = users.map(({ id, name }) => ({ id, name }));
  res.json(safeUsers);
});

// Provide a separate, more-privileged endpoint for full profile data
app.get('/users/:id/profile', requireAuth, requireRole('admin'), ...);
```

---

## 🟡 Medium

### M-1 — No CORS Policy
**OWASP A05: Security Misconfiguration**

