const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const app = express();

// 1. Security headers
app.use(helmet());

// 2. Rate limiting
const limiter = rateLimit({ windowMs: 60_000, max: 60 });
app.use(limiter);

// 3. Authenticated /users (example using a simple middleware stub)
function requireAuth(req, res, next) {
  const token = req.headers['authorization'];
  if (!token || !isValidToken(token)) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // drop timestamp if not needed
});

app.get('/users', requireAuth, (req, res) => {
  res.json([/* ... */]);
});

// 4. Centralized error handler — must be last
app.use((err, req, res, next) => {
  console.error(err); // log internally, never send stack to client
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000, '127.0.0.1', () => { // bind to loopback, not 0.0.0.0
  console.log('Server running on port 3000');
});
```

